from langchain.agents import AgentExecutor
from collections import defaultdict

class LoopDetector:
    def __init__(self, max_iterations=3):
        self.tool_calls = defaultdict(list)
        self.max_iterations = max_iterations

    def check_loop(self, tool_call):
        tool_name = tool_call['name']
        args_hash = hash(str(tool_call['args']))
        self.tool_calls[tool_name].append(args_hash)
        recent_calls = self.tool_calls[tool_name][-self.max_iterations:]
        return len(set(recent_calls)) < len(recent_calls)

# Usage
detector = LoopDetector()
agent_executor = AgentExecutor(...)
def safe_invoke(input):
    result = agent_executor.invoke(input)
    if detector.check_loop(result.get('tool_call', {})):
        raise ValueError('Tool call loop detected')
    return result
